const cp = require('child_process');
const patron = $json.body.patron;
const dir = $json.body.directorio || '/home/lucy-ubuntu/Escritorio/NIN';
try {
  const cmd = `grep -rn "${patron}" "${dir}" --include='*.py' --include='*.md' --include='*.json' 2>/dev/null | head -50`;
  const output = cp.execSync(cmd).toString();
  return { output };
} catch (e) {
  return { output: "No se encontraron resultados o hubo un error." };
}
